function out(){
  var str = [].slice.call(arguments).join(' ');
	console.log('\033[36m' + str + '\033[0m');
}
function alert(){
  var str = [].slice.call(arguments).join(' ');
	console.log('\033[31m' + str + '\033[0m');
}
function main(){
  var str = [].slice.call(arguments).join(' ');
	console.log(str);
}
exports.out = out;
exports.alert = alert;
exports.main = main;